    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        string s; cin>>s;
        string ans; ans.reserve(N/2);
        for(int i=0;i<N;i+=2){
            char a=s[i], b=s[i+1];
            if(a=='0' && b=='0') ans.push_back('A');
            else if(a=='0' && b=='1') ans.push_back('T');
            else if(a=='1' && b=='0') ans.push_back('C');
            else ans.push_back('G');
        }
        cout<<ans<<"\n";
    }
    return 0;
}

