import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        s = next(it)
        ans_chars = []
        for i in range(0, N, 2):
            pair = s[i:i+2]
            if pair == '00': ans_chars.append('A')
            elif pair == '01': ans_chars.append('T')
            elif pair == '10': ans_chars.append('C')
            else: ans_chars.append('G')
        out_lines.append(''.join(ans_chars))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

